der-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; margin-bottom: 1rem; text-align: justify;\"><img src=\"https://bizweb.dktcdn.net/100/514/823/files/67.jpg?v=1762076471900\" alt=\"\"></p>', 'Không gian sống', 'assets/images/blog-uploads/blog_20260523_194907_0695b8db.png', '2 phút đọc', '2026-05-23', 0, 'published', '2026-05-23 17:45:28', '2026-05-23 17:49:07');
INSERT INTO `blog_posts` (`id`, `slug`, `title`, `excerpt`, `content`, `category`, `image`, `read_time`, `published_at`, `is_featured`, `status`, `created_at`, `updated_at`) VALUES
(5, 'diem-nhan-hoai-co-kham-pha-ve-dep-cua-chiec-den-treo-phong-khoang-bauhaus', 'Điểm Nhấn Hoài Cổ: Khám Phá Vẻ Đẹp Của Chiếc Đèn Treo Phóng Khoáng BAUHAUS', 'Trong thế giới thiết kế nội thất, ánh sáng không chỉ đơn thuần là nguồn chiếu rọi mà còn là một tác phẩm nghệ thuật, một tuyên ngôn về phong cách. Chiếc đèn treo mà chúng ta đang chiêm ngưỡng trong những bức ảnh này chính là một minh chứng hoàn hảo cho sự giao thoa giữa vẻ đẹp cổ điển và nét hiện đại phóng khoáng. Đây là loại đèn có thể dễ dàng trở thành tâm điểm thu hút mọi ánh nhìn trong bất kỳ không gian nào.', '<p><img src=\"https://bizweb.dktcdn.net/100/514/823/articles/red-and-beige-vintage-bold-typographic-beauty-salon-logo-3.jpg?v=1761722764797\" alt=\"Điểm Nhấn Hoài Cổ: Khám Phá Vẻ Đẹp Của Chiếc Đèn Treo Phóng Khoáng BAUHAUS\"></p>Điểm Nhấn Hoài Cổ: Khám Phá Vẻ Đẹp Của Chiếc Đèn Treo Phóng Khoáng BAUHAUSTạ Hà TrangThứ Tư, 29/10/20253 phút đọc<p style=\"--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; margin-bottom: 1rem; text-align: justify;\">Trong thế giới thiết kế nội thất, ánh sáng không chỉ đơn thuần là nguồn chiếu rọi mà còn là một tác phẩm nghệ thuật, một tuyên ngôn về phong cách. Chiếc đèn treo mà chúng ta đang chiêm ngưỡng trong những bức ảnh này chính là một minh chứng hoàn hảo cho sự giao thoa giữa vẻ đẹp cổ điển và nét hiện đại phóng khoáng. Đây là loại đèn có thể dễ dàng trở thành tâm điểm thu hút mọi ánh nhìn trong bất kỳ không gian nào.</p><p style=\"--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; margin-bottom: 1rem; text-align: justify;\">&nbsp;</p><p style=\"--tw-border-spacing-x: 0; --tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 