--
-- Cấu trúc bảng cho bảng `products`
--

CREATE TABLE `products` (
  `id` bigint(20) NOT NULL,
  `category_id` bigint(20) NOT NULL,
  `name` varchar(255) NOT NULL,
  `slug` varchar(300) NOT NULL,
  `short_description` text DEFAULT NULL,
  `description` longtext DEFAULT NULL,
  `sku` varchar(60) NOT NULL,
  `base_price` decimal(12,2) NOT NULL DEFAULT 0.00,
  `stock_status` enum('in_stock','out_of_stock','preorder') NOT NULL DEFAULT 'in_stock',
  `material` varchar(120) DEFAULT NULL,
  `color` varchar(120) DEFAULT NULL,
  `warranty_months` int(11) DEFAULT NULL,
  `rating_average` decimal(3,2) NOT NULL DEFAULT 0.00,
  `rating_count` int(11) NOT NULL DEFAULT 0,
  `is_featured` tinyint(1) NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `published_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Đang đổ dữ liệu cho bảng `products`
--

INSERT INTO `products` (`id`, `category_id`, `name`, `slug`, `short_description`, `description`, `sku`, `base_price`, `stock_status`, `material`, `color`, `warranty_months`, `rating_average`, `rating_count`, `is_featured`, `is_active`, `published_at`, `created_at`, `updated_at`) VALUES
(1, 1, 'Đèn thả bàn ăn Axis, đèn thả quầy khung kim loại thiết kế hiện đại', 'den-treo-tran-axis', 'Đèn thả đảo Axis dài 1m, thiết kế hiện đại, chao thủy tinh trong suốt, ánh sáng LED tự nhiên 220-240V. Phù hợp treo trên đảo bếp, quầy bar, bàn ăn, tạo không gian sáng đẹp và sang trọng.', 'THÔNG SỐ\r\n- Chiều dài: 1m\r\n- Chất liệu: acrylic cứng + khung kim loại\r\n- Nguồn sáng: LED tích hợp\r\n- Điện áp: 220-240V\r\n- Kiểu đấu nối: Đấu dây trực tiếp\r\n- Ánh sáng: Natural light\r\n\r\nGỢI Ý SỬ DỤNG\r\n- Treo trên đảo bếp hoặc quầy bar để chiếu sáng đồng đều\r\n- Dùng cho phòng ăn, bếp, quán cafe, nhà hàng phong cách hiện đại\r\n- Phù hợp không gian cần ánh sáng tự nhiên, không chói\r\n\r\nLƯU Ý BẢO QUẢN\r\n- Lắp đặt bởi thợ điện chuyên nghiệp để đảm bảo an toàn\r\n- Lau chùi chao thủy tinh bằng khăn mềm, tránh chất tẩy mạnh\r\n- Ngắt nguồn điện khi vệ sinh hoặc bảo dưỡng', 'DPB17', 2400000.00, 'in_stock', 'Hợp kim nhôm', 'Bạc', 12, 5.00, 1, 1, 1, '2026-05-19 17:05:19', '2026-05-19 10:05:19', '2026-05-20 05:42:21'),
(2, 1, 'Đèn thả trần Bauhaus chao thủy tinh, dây treo điều chỉnh độ cao', 'den-treo-bauhaus', 'Đèn với màu vàng kem nhạt, độ bão hòa thấp mang lại cảm giác phân cấp rõ ràng với các đồ vật khác. Và trong không gian đó, tông màu nhẹ nhàng của chiếc đèn lại càng được tôn lên nổi bật.', 'THÔNG SỐ:\r\n\r\nKích thước: 25* 35 cm\r\nNguồn sáng: đèn led E27\r\nChất liệu chao đèn: thủy tinh\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nĐèn với thiết kế độc đáo, ấn tượng là điểm nhấn thú vị cho căn phòng. Rất phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng dịu, ấm áp tạo không gian thoải mái, thư giãn\r\nCó thể nâng lên, hạ xuống, thay đổi chiều dài dây đèn mà không cần phải tháo lắp đèn nhờ thiết kế dây treo lò xo co giãn độc đáo', 'DPA04', 1200000.00, 'in_stock', 'Kim loại sơn tĩnh điện', 'Kem Nhạt', 12, 0.00, 0, 1, 1, '2026-05-19 17:05:19', '2026-05-19 10:05:19', '2026-05-20 05:43:04'),
(3, 1, 'Đèn thả trần PH5 màu be', 'ph5-pendant-lamp', 'ĐÈN THẢ TRẦN BÀN ĂN ĐAN MẠCH (PH LAMP)\r\n\r\nThêm phần lấp lánh cho không gian của bạn với Đèn treo PH5  Mercero! Với chiếc đèn thả trần hình UFO bắt mắt, tuyệt đẹp này, bạn chắc chắn sẽ gây ấn tượng với bất kỳ ai bước vào phòng. Với thiết kế đẹp mắt và vượt thời gian, chiếc đèn hoàn hảo cho mọi phong cách trang trí, từ chủ nghĩa tối giản hiện đại đến sự tinh tế cổ điển. Thắp sáng màn đêm và tỏa sáng căn phòng của bạn!', 'THÔNG SỐ:\r\n\r\nKích thước: đường kính 42/ 35 cm\r\nBóng đèn: led  ánh sáng màu vàng. Đui đèn E27. (Nếu thích bóng sáng hơn cho không gian lớn bạn có thể m ua bóng thay thế)\r\nDây điện 1.5 m\r\nChất liệu: Hợp kim nhôm\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nĐèn thả bàn ăn phong cách Bắc Âu hiện đại, sang trọng.\r\nĐấu nối dây điện, có thể cắt bớt để điều chỉnh độ dài tùy ý.', 'DPA01', 1050000.00, 'preorder', 'Họp kim nhôm', 'Be', 12, 4.50, 2, 1, 1, '2026-05-19 17:05:19', '2026-05-19 10:05:19', '2026-06-09 23:39:44'),
(4, 1, 'Đèn thả akari hình nón, chao đèn giấy phong cách Nhật Bản', 'dn-th-akari-hnh-nn-chao-dn-giy-phong-cch-nht-bn', 'Đèn thả akari hình nón, chao đèn giấy phong cách Nhật Bản', 'Đèn treo hình nón chiếu sáng tinh tế và giàu tính văn hóa, lấy cảm hứng từ truyền thống làm giấy Washi cổ xưa. Nổi tiếng với độ bền, kết cấu và tuổi thọ cao, giấy Washi được chế tác thủ công tinh xảo thành chao đèn hình nón cho chiếc đèn treo này. Bề mặt của nó có những đường gân nhẹ nhàng, thêm một kết cấu hấp dẫn giúp nâng cao hình dạng đơn giản nhưng hình học của nó. Thiết kế của đèn cho phép ánh sáng khuếch tán mềm mại xuyên qua giấy Washi, tạo ra ánh sáng ấm áp và dễ chịu, phù hợp với mọi không gian.\r\n\r\n- Chao đèn làm từ  giấy gạo, chịu nhiệt độ cao không dễ gãy, truyền ánh sáng đều và nhẹ nhàng, dễ lau chùi, không dễ ố vàng.\r\n- Đui đèn E27 chịu nhiệt độ cao, an toàn và bền bỉ, tuổi thọ cao, có thể thay thế bằng nhiều loại bóng đèn: đèn LED, đèn sợi đốt, đèn tiết kiệm năng lượng.\r\n- Dây treo có thể điều chỉnh tối đa 150cm, bạn có thể điều chỉnh ánh sáng ở các độ cao khác nhau tùy theo nhu cầu để tạo hiệu ứng ánh sáng tốt hơn.\r\n- Không gian áp dụng: câu lạc bộ, văn phòng, đảo bếp, phòng ngủ, phòng khách, quán cà phê, cửa hàng đồ cổ, cửa hàng quần áo, hiên nhà, nhà để xe, lối vào, phòng khách, sàn nhà, cầu thang, tầng hầm, hành lang.\r\n\r\nTHÔNG TIN SẢN PHẨM:\r\n\r\nKích thước: Đường kính chao đèn 35 cm, cao 22 cm, dây dài 1.5m (có thể điều chỉnh)\r\nChất liệu: Chao đèn giấy gạo\r\nBóng đèn: LED đui E27. Ánh sáng vàng', 'DPB14', 960000.00, 'in_stock', 'Giấy', 'Trắng', 12, 0.00, 0, 0, 1, '2026-05-20 02:33:56', '2026-05-19 19:33:56', '2026-05-20 05:37:00'),
(5, 4, 'Đèn sàn Matsutake', 'dn-sn-matsutake', 'Đèn sàn Matsutake DSA04', 'THÔNG SỐ:\r\n\r\nKích thước: XEM HÌNH\r\nBóng đèn led G9* 3 bóng đèn, 3 màu: trắng, vàng, trung tính\r\nVật liệu: thủy tinh, gỗ\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n \r\n\r\nCÔNG DỤNG:\r\n\r\nCung cấp ánh sáng ấm áp, đặt bên cạnh giường ngủ hoặc làm một chiếc đèn đọc sách hoàn hảo.\r\nPhù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DSA04', 3100000.00, 'in_stock', 'Thủy tinh', 'Trắng', 12, 0.00, 0, 0, 1, '2026-05-20 02:35:57', '2026-05-19 19:35:57', '2026-05-20 05:37:54'),
(6, 4, 'Đèn sàn để cạnh ghế sofa, chụp đèn acrylic 2 lớp màu trong suốt, đèn đứng trang trí', 'dn-sn-d-cnh-gh-sofa-chp-dn-acrylic-2-lp-mu-trong-sut-dn-dng-trang-tr', 'ĐÈN SÀN CHAO ACRYLIC 2 LỚP TRONG SUỐT DÁNG NẤM', 'THÔNG SỐ:\r\n\r\nKích thước: Cao 120 cm, đường kính đế 23 cm\r\nNguồn sáng: đèn led đui e27 ánh sáng vàng ấm 12w\r\nChất liệu chao đèn: nhựa acrylic, 2 lớp\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nĐèn với thiết kế cổ điển, chao đèn 2 lớp cho hiệu ứng ánh sáng ấn tượng là điểm nhấn thú vị cho căn phòng. Rất phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DSA02', 1500000.00, 'in_stock', 'nhựa acrylic', 'hổ phách', 12, 0.00, 0, 0, 1, '2026-05-20 02:38:08', '2026-05-19 19:38:08', '2026-05-20 05:45:03'),
(7, 3, 'Đèn bàn Nesso màu vàng dáng nấm, đèn bàn trang trí ánh sáng ấm - winsum home', 'dn-bn-nesso-mu-vng-dng-nm-dn-bn-trang-tr-nh-sng-m-winsum-home', 'ĐÈN ĐỂ BÀN NESSO HÌNH NẤM', 'THÔNG SỐ:\r\n\r\n- Kích thước: 23*32 cm, dây đèn 1.5m\r\n\r\n- Ng uồn sáng: đèn led ánh sáng 3 màu vàng ấm, trắng, trung tính\r\n\r\n- Chất liệu chao đèn: nhựa acrylic\r\n\r\n \r\n\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\n \r\n\r\nCÔNG DỤNG:\r\n\r\n- Đèn với thiết kế đơn giản, phù hợp với phong cách retro tối giản, tinh tế.\r\n\r\n- Chao đèn màu cam mang lại cảm giác ấm áp, cổ điển, phù hợp với không gian ấm cúng trong bếp, hoàn hảo với những bộ bàn ăn bằng gỗ tự nhiên tông trầm ấm.\r\n\r\n- Rất phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\n\r\n- Ánh sáng dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DBB06', 810000.00, 'in_stock', 'nhựa acylic', 'Cam', 12, 0.00, 0, 0, 1, '2026-05-20 02:39:42', '2026-05-19 19:39:42', '2026-05-23 17:41:59'),
(8, 3, 'Đèn bàn Tolomeo', 'dn-bn-tolomeo', 'ĐÈN BÀN TOLOMEO', 'THÔNG SỐ:\r\n\r\n- Kích thước: cánh tay 25x25 cm, đường kính trên chao đèn 14cm, đế 20cm\r\n\r\n- Chất liệu: nhôm mạ crom\r\n\r\n- Bóng đèn: E27 LED 7W\r\n\r\n- Mẫu mã thiết kế: Phong cách industrial\r\n\r\n \r\n\r\nCÔNG DỤNG:\r\n\r\n- Đèn bàn làm việc, thiết kế phù hợp với nhiều nhu cầu sử dụng\r\n\r\n- Có thể điều chỉnh linh hoạt phần cánh tay gập để phù hợp với chiều cao, tư thế của người dùng\r\n\r\n- Ánh sáng đèn màu vàng mang lại sự ấm áp cho căn phòng của bạn.', 'DBB015', 1200000.00, 'in_stock', 'Inox', 'Bạc', 12, 0.00, 0, 0, 1, '2026-05-20 02:40:55', '2026-05-19 19:40:55', '2026-05-23 17:41:04'),
(9, 3, 'Đèn bàn Louis Poulsen chụp đèn thủy tinh', 'dn-bn-louis-poulsen-chp-dn-thy-tinh', 'ĐÈN BÀN LOUIS POULSEN\r\nĐèn bàn với thiết kế đơn giản, dễ phối nhiều không gian. Ánh sáng đổi màu tạo cảm giác dễ chịu từ sáng đến tối. Phần chụp thủy tinh tán đều ánh sáng, chân đèn chắc chắn, phù hợp đặt bàn học, đầu giường hoặc góc làm việc.', 'THÔNG SỐ:\r\n- Kích thước: D28.5cm x H45cm\r\n- Bóng đèn: LED E27 5W\r\n- Ánh sáng: vàng – trung tính – trắng (đổi màu mỗi lần bật công tắc)\r\n- Nhiệt độ màu: 3000K\r\n- Chỉ số hoàn màu: CRI > 85\r\n- Chất liệu: thủy tinh, sắt mạ crom\r\nGỢI Ý SỬ DỤNG:\r\n- Làm đèn đầu giường tạo không khí ấm áp, dễ chịu\r\n- Đặt ở bàn học, bàn làm việc để có ánh sáng vừa đủ\r\n- Trang trí kệ sách, bàn trà theo phong cách tối giản – Bắc Âu\r\n LƯU Ý BẢO QUẢN:\r\n- Lau nhẹ bằng khăn khô hoặc khăn ẩm mềm, tránh dùng hóa chất mạnh\r\n- Không đặt đèn nơi ẩm ướt hoặc có nguy cơ rơi vỡ\r\n- Khi thay bóng đèn, đảm bảo nguồn điện đã được ngắt hoàn toàn', 'DBB017', 1800000.00, 'in_stock', 'thủy tinh, sắt mạ crom', 'Cam', 12, 0.00, 0, 0, 1, '2026-05-20 02:42:22', '2026-05-19 19:42:22', '2026-05-23 17:39:42'),
(10, 3, 'Đèn bàn thủy tinh thân gỗ màu óc chó, công tắc nút gạt kiểu cổ điển winsum home', 'dn-bn-thy-tinh-thn-g-mu-c-ch-cng-tc-nt-gt-kiu-c-din-winsum-home', 'Đèn bàn decor thân gỗ kết hợp chao thủy tinh màu khói, ánh sáng vàng 3000K ấm áp. Thiết kế tối giản sang trọng, phù hợp nhiều không gian.', 'THÔNG SỐ\r\n\r\nSKU: DBB019\r\nKích thước: D20cm × H22cm\r\nCông suất: LED 5W\r\nNhiệt độ màu: 3000K\r\nCRI: >90\r\nChất liệu: Gỗ + thủy tinh màu khói\r\n GỢI Ý SỬ DỤNG\r\n\r\nĐặt ở tab đầu giường, bàn làm việc, kệ trang trí.\r\nPhù hợp phòng ngủ, phòng khách, homestay, studio.\r\nTạo ánh sáng ấm, dễ chịu, tăng thẩm mỹ không gian.\r\nLƯU Ý BẢO QUẢN\r\n\r\nLau bằng khăn khô, tránh khăn ướt để hạn chế oxy hóa.\r\nTránh va đập vào phần chao thủy tinh.\r\nĐặt nơi khô ráo, tránh ẩm cao.', 'DBB019', 1500000.00, 'preorder', 'Gỗ + thủy tinh màu khói', 'Màu gỗ tự nhiên', 12, 0.00, 0, 0, 1, '2026-05-20 02:42:47', '2026-05-19 19:42:47', '2026-05-23 17:38:01'),
(11, 2, 'Đèn Donut thủy tinh thay đổi ánh sáng phong cách Bauhaus, có đế để bàn, treo tường tiện lợi', 'dn-donut-thy-tinh-thay-di-nh-sng-phong-cch-bauhaus-c-d-d-bn-treo-tng-tin-li', 'Đèn Donut thủy tinh thay đổi ánh sáng phong cách Bauhaus, có đế để bàn, treo tường tiện lợi - DTA01', 'THÔNG SỐ:\r\n\r\nChụp đèn: thủy tinh\r\nKích thước: chiều cao 22 cm, đường kính 17 cm\r\nĐiều chỉnh độ sáng 3 màu\r\nBật/ tắt đèn bằng cách nhấn nút cảm ứng ở giữa đèn\r\nCÔNG DỤNG:\r\n\r\nĐèn ngủ để bàn được thiết kế phong cách vintage xinh xắn, phù hợp với không gian phòng ngủ của bạn.\r\nÁnh sáng đèn màu vàng mang lại sự ấm áp cho căn phòng của bạn.\r\nHƯỚNG DẪN SỬ DỤNG:\r\n\r\nChạm nhẹ vào nút tròn giữa đèn để bật/ tắt đèn', 'DTA01', 680000.00, 'in_stock', 'Thủy tinh', 'Cam', 12, 0.00, 0, 1, 1, '2026-05-20 11:57:23', '2026-05-20 04:57:23', '2026-05-23 17:32:12'),
(12, 2, 'Đèn tường Tolomeo điều chỉnh xoay các hướng, phong cách Industrial', 'dn-tng-tolomeo-diu-chnh-xoay-cc-hng-phong-cch-industrial', 'Là một thiết kế, đáng ngưỡng mộ vì sự nhẹ nhàng và thuần khiết của các đường nét, được đánh giá cao vì tính hiện đại vượt thời gian Lấy cảm hứng từ mô hình truyền thống, Tolomeo là phiên bản thứ hai của đèn lò xo trước đây, giờ đây được giải thích bằng công nghệ hiện đại. Kết quả là một đối tượng sáng tạo, được hiện thực hóa với một số phần thiết yếu.', 'THÔNG SỐ:\r\n\r\nKích thước: xem hình\r\nChất liệu: nhôm mạ crom\r\nBóng đèn: E14 LED 7W\r\nMẫu mã thiết kế: Phong cách industrial\r\nCÔNG DỤNG:\r\n\r\nĐèn gắn đầu giường, bên cạnh bàn làm việc, thiết kế phù hợp với nhiều nhu cầu sử dụng\r\nCó thể điều chỉnh linh hoạt phần cánh tay gập để phù hợp với chiều cao, tư thế của người dùng\r\nÁnh sáng đèn màu vàng mang lại sự ấm áp cho căn phòng của bạn.', 'DTB02', 1350000.00, 'in_stock', 'nhôm mạ crom', 'Bạc', 12, 0.00, 0, 0, 1, '2026-05-20 11:58:25', '2026-05-20 04:58:25', '2026-05-23 17:36:19'),
(13, 2, 'Đèn treo tường thân gỗ óc chó gấp gọn, chao gốm Vintage', 'dn-treo-tng-thn-g-c-ch-gp-gn-chao-gm-vintage', 'Đèn treo tường thân gỗ óc chó gấp gọn, chao gốm Vintage - DTB01', 'THÔNG SỐ:\r\n\r\nKích thước chụp đèn khoảng 26cm, khoảng cách từ tường đến chụp đèn: 33cm, đường kính đế gỗ là 10cm.\r\nChất liệu: Thân đèn gỗ óc chó, chao đèn gốm\r\nBóng đèn LED 4W\r\nMẫu mã thiết kế: Phong cách vintage\r\nCÔNG DỤNG:\r\n\r\nĐèn gắn đầu giường, bên cạnh bàn làm việc, thiết kế phù hợp với nhiều nhu cầu sử dụng. Có thể điều chỉnh linh hoạt phần cánh tay gập để phù hợp với chiều cao, tư thế của người dùng.\r\nĐèn được thiết kế đơn giản phù hợp với không gian phòng ngủ của gia đình bạn.\r\nÁnh sáng đèn màu vàng mang lại sự ấm áp cho căn phòng của bạn.\r\nBóng đèn nhựa nên không tỏa nhiệt trong quá trình sử dụng. Tiết kiệm điện năng đáng kể.', 'DTB01', 1350000.00, 'in_stock', 'Thân đèn gỗ óc chó, chao đèn gốm', 'Gỗ', 12, 0.00, 0, 0, 1, '2026-05-20 12:01:20', '2026-05-20 05:01:20', '2026-05-23 17:35:56'),
(14, 6, 'Kệ đứng treo TV Brateck đế kim loại chống nghiêng, tương thích TV 32-85 inch', 'k-dng-treo-tv-brateck-d-kim-loi-chng-nghing-tng-thch-tv-32-85-inch', 'Kệ đứng treo TV Brateck đế kim loại chống nghiêng, tương thích TV 32-85 inch - Winsum Home Decor', 'THÔNG SỐ:\r\n\r\nKích thước: xem hình\r\nPhù hợp với TV từ 32-85 inch\r\nChất liệu: sắt, gỗ\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nKệ để tivi thiết kế đơn giản, linh hoạt dễ dàng di chuyển, bạn có thể để vào phòng ngủ, phòng ăn, phòng khách,... đơn giản, nhanh chóng.\r\nGiúp thay đổi, làm mới không gian sống, giúp căn nhà luôn thú vị, không nhàm chán.\r\nHạn chế khoan đục tường\r\nLƯU Ý KHI NHẬN HÀNG:\r\n\r\nLắp đặt: Sản phẩm không bao gồm lắp đặt. Nếu cần hỗ trợ, vui lòng liên hệ shop.\r\nDụng cụ: Sản phẩm có kèm lục giác. Các dụng cụ khác (tua vít, máy khoan…) khách tự chuẩn bị.\r\nỐc vít: Trong hộp sản phẩm có kèm nhiều loại ốc vít với kích thước khác nhau, phù hợp với đa số TV phổ biển. Tuy nhiên do các loại tivi/màn hình hiện nay có nhiều hãng và model khác nhau, tiêu chuẩn không đồng nhất, nên có thể xảy ra trường hợp ốc vít kèm theo không phù hợp với thiết bị của bạn. Nếu gặp tình huống này, vui lòng liên hệ ngay với shop để được hướng dẫn.', 'K04', 5400000.00, 'in_stock', 'sắt, gỗ', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:03:06', '2026-05-20 05:03:06', '2026-05-23 17:35:39'),
(15, 6, 'Giá đỡ TV tripod 3 chân gỗ, có thể xoay sang trái phải TV 43-75 inch', 'gi-d-tv-tripod-3-chn-g-c-th-xoay-sang-tri-phi-tv-43-75-inch', 'Kệ để tivi thiết kế đơn giản, linh hoạt dễ dàng di chuyển, bạn có thể để vào phòng ngủ, phòng ăn, phòng khách,... đơn giản, nhanh chóng, giúp thay đổi, làm mới không gian sống, giúp căn nhà luôn thú vị, không nhàm chán.', 'THÔNG SỐ:\r\n\r\nKích thước: xem hình\r\nPhù hợp với TV từ 43-75 inch\r\nChất liệu: sắt, gỗ\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nKệ để tivi thiết kế đơn giản, linh hoạt dễ dàng di chuyển, bạn có thể để vào phòng ngủ, phòng ăn, phòng khách,... đơn giản, nhanh chóng.\r\nGiúp thay đổi, làm mới không gian sống, giúp căn nhà luôn thú vị, khôn nhàm chán.\r\nHạn chế khoan đục tường\r\nLƯU Ý KHI NHẬN HÀNG:\r\n\r\nLắp đặt: Sản phẩm không bao gồm lắp đặt. Nếu cần hỗ trợ, vui lòng liên hệ shop.\r\nDụng cụ: Sản phẩm có kèm lục giác. Các dụng cụ khác (tua vít, máy khoan…) khách tự chuẩn bị.\r\nỐc vít: Trong hộp sản phẩm có kèm nhiều loại ốc vít với kích thước khác nhau, phù hợp với đa số TV phổ biển. Tuy nhiên do các loại tivi/màn hình hiện nay có nhiều hãng và model khác nhau, tiêu chuẩn không đồng nhất, nên có thể xảy ra trường hợp ốc vít kèm theo không phù hợp với thiết bị của bạn. Nếu gặp tình huống này, vui lòng liên hệ ngay với shop để được hướng dẫn.', 'K03', 3600000.00, 'in_stock', 'sắt, gỗ', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:04:57', '2026-05-20 05:04:57', '2026-05-23 17:35:17'),
(16, 6, 'Giá đỡ TV chân gỗ cao cấp phong cách Hàn Quốc, thiết kế kiểu khung vẽ nghệ thuật', 'gi-d-tv-chn-g-cao-cp-phong-cch-hn-quc-thit-k-kiu-khung-v-ngh-thut', 'Kệ để tivi thiết kế đơn giản, linh hoạt dễ dàng di chuyển, bạn có thể để vào phòng ngủ, phòng ăn, phòng khách,... đơn giản, nhanh chóng, giúp thay đổi, làm mới không gian sống, giúp căn nhà luôn thú vị, không nhàm chán.', 'THÔNG SỐ:\r\n\r\nKích thước: xem hình\r\nPhù hợp với TV từ 49-70 inch\r\nChất liệu: sắt, gỗ\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nKệ để tivi thiết kế đơn giản, linh hoạt dễ dàng di chuyển, bạn có thể để vào phòng ngủ, phòng ăn, phòng khách,... đơn giản, nhanh chóng.\r\nGiúp thay đổi, làm mới không gian sống, giúp căn nhà luôn thú vị, không nhàm chán.\r\nHạn chế khoan đục tường\r\nLƯU Ý KHI NHẬN HÀNG:\r\n\r\nLắp đặt: Sản phẩm không bao gồm lắp đặt. Nếu cần hỗ trợ, vui lòng liên hệ shop.\r\nDụng cụ: Sản phẩm có kèm lục giác. Các dụng cụ khác (tua vít, máy khoan…) khách tự chuẩn bị.\r\nỐc vít: Trong hộp sản phẩm có kèm nhiều loại ốc vít với kích thước khác nhau, phù hợp với đa số TV phổ biển. Tuy nhiên do các loại tivi/màn hình hiện nay có nhiều hãng và model khác nhau, tiêu chuẩn không đồng nhất, nên có thể xảy ra trường hợp ốc vít kèm theo không phù hợp với thiết bị của bạn. Nếu gặp tình huống này, vui lòng liên hệ ngay với shop để được hướng dẫn.', 'K02', 5100000.00, 'in_stock', 'sắt, gỗ', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:05:50', '2026-05-20 05:05:50', '2026-05-20 05:44:29'),
(17, 5, 'Đèn chùm chữ X phong cách Industrial thả quầy bar, quán ăn, phòng khách', 'dn-chm-ch-x-phong-cch-industrial-th-quy-bar-qun-n-phng-khch', '', 'THÔNG SỐ:\r\n\r\nKích thước: 60 x 30 cm\r\nBóng LED 12W - 3 chế độ sáng: trắng, vàng, trung tính\r\nChất liệu chao đèn: acrylic trong suốt, thân sắt mạ điện chống gỉ', 'DCB03', 1250000.00, 'in_stock', NULL, NULL, 12, 0.00, 0, 1, 1, '2026-05-20 12:06:42', '2026-05-20 05:06:42', '2026-05-23 17:31:36'),
(18, 1, 'Đèm chùm phòng khách acrylic style Bắc Âu, đèn thả bàn ăn sang trọng', 'dm-chm-phng-khch-acrylic-style-bc-u-dn-th-bn-n-sang-trng', 'Đèn chùm với thiết kế trang nhã và chất liệu tinh tế, mang lại ánh sáng độc đáo cho không gian hiện đại. Chiếc đèn này được làm từ chất liệu sắt cao cấp tạo nên một chân đế tinh tế, với chao đèn bằng thủy tinh mịn, trang trí bằng các mảng acrylic màu hổ phách, giúp hiệu ứng ánh sáng trang nhã và ấm áp. Đây không chỉ là chiếc đèn tỏa sáng mà còn là vật trang trí có thể nâng tầm bầu không khí của toàn bộ căn phòng.', 'THÔNG SỐ:\r\n\r\nKích thước: đèn chùm 5 bóng: 60x40 cm\r\nBóng LED 12W - 3 chế độ sáng: trắng, vàng, trung tính\r\nChất liệu chao đèn: acrylic, sắt mạ điện', 'DCB02', 2000000.00, 'in_stock', NULL, NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:08:30', '2026-05-20 05:08:30', '2026-05-23 17:34:49'),
(19, 5, 'Đèn Chùm hạt đậu Bauhaus chụp thủy tinh sang trọng', 'dn-chm-ht-du-bauhaus-chp-thy-tinh-sang-trng', 'ĐÈN CHÙM BẮC ÂU', 'THÔNG SỐ:\r\n\r\nKích thước: đèn chùm 5 bóng: 55x35 cm, đèn chùm 3 bóng: 42x35 cm\r\nNguồn sáng: Bóng LED 12W - 3 chế độ sáng\r\n Chất liệu chao đèn: gốm\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nĐèn với thiết kế độc đáo, ấn tượng là điểm nhấn thú vị cho căn phòng. Rất phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DCA01', 2500000.00, 'in_stock', 'gốm', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:09:23', '2026-05-20 05:09:23', '2026-05-23 17:34:12'),
(20, 5, 'Đèn Chùm Bắc Âu phong cách Bauhaus chụp thủy tinh sang trọng', 'dn-chm-bc-u-phong-cch-bauhaus-chp-thy-tinh-sang-trng', 'Đèn chùm bauhaus với thiết kế trang nhã và chất liệu tinh tế, mang lại ánh sáng độc đáo cho không gian hiện đại. Chiếc đèn này được làm từ chất liệu sắt cao cấp tạo nên một chân đế tinh tế, với chao đèn bằng thủy tinh mịn, thể hiện hiệu ứng ánh sáng trang nhã và ấm áp. Tông màu ấm áp của chao đèn bổ sung cho ánh sáng kim loại và tạo thêm nét nghệ thuật cho nội thất của bạn. Đèn không chỉ là vật cố định ánh sáng mà còn là vật trang trí có thể nâng tầm bầu không khí của toàn bộ căn phòng.', 'THÔNG SỐ:\r\n\r\n- Kích thước: đèn chùm 5 bóng: 55x35 cm, đèn chùm 3 bóng: 42x35 cm\r\n\r\n- Nguồn sáng: Bóng LED 12W - 3 chế độ sáng\r\n\r\n- Chất liệu chao đèn: thủy tinh.', 'DCB01', 1500000.00, 'in_stock', NULL, NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:10:28', '2026-05-20 05:10:28', '2026-05-20 05:43:57'),
(21, 2, 'Đèn tường KVADRILLE phong cách Memphis cổ điển trang trí nhà cửa', 'dn-tng-kvadrille-phong-cch-memphis-c-din-trang-tr-nh-ca', 'Đèn treo tường decor nghệ thuật thiết kế dạng khối vuông nhiều lớp độc đáo, tạo hiệu ứng ánh sáng nổi bật và bắt mắt.', 'Ánh sáng LED ổn định, không nhấp nháy, phù hợp làm điểm nhấn cho không gian hiện đại, phòng ngủ hoặc góc làm việc. \r\n\r\nCó thể treo tường hoặc đặt bàn linh hoạt.\r\n\r\nTHÔNG SỐ\r\n\r\nChất liệu: sắt + mica (acrylic)\r\nĐui đèn: E27\r\nNguồn sáng: LED \r\nKích thước: ~25 x 25 cm\r\nMàu ánh sáng: đa màu (đỏ / xanh / trắng)\r\nKiểu lắp: treo tường / để bàn Diện tích chiếu sáng: phòng ngủ, phòng khách \r\nGỢI Ý SỬ DỤNG\r\n\r\nTrang trí phòng ngủ, phòng khách Làm đèn decor nghệ thuật, tạo điểm nhấn Setup góc làm việc, bàn học Dùng cho quán cafe, studio chụp ảnh\r\n\r\nLƯU Ý BẢO QUẢN\r\n\r\nTránh va đập mạnh làm nứt mica Không để nơi ẩm ướt Lau bằng khăn mềm, khô Ngắt điện khi lắp đặt hoặc vệ sinh', 'Đang cập nhật', 1890000.00, 'in_stock', 'sắt + mica (acrylic)', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:11:28', '2026-05-20 05:11:28', '2026-05-23 17:33:03'),
(22, 2, 'Đèn ốp tường tròn acrylic, đèn hành lang winsum home', 'dn-p-tng-trn-acrylic-dn-hnh-lang-winsum-home', 'Đèn gắn tường tròn acrylic\r\n\r\nCó kiểu dáng đơn giản với ốp tường hợp kim nhôm nhẹ, bền bỉ, chao đèn acrylic trong suốt độc đáo sẽ mang nét đẹp của thời đại đến với không gian trang trí của bạn.\r\n\r\nSử dụng cho hành lang, đầu giường phòng ngủ, phòng khách, phòng tắm, cầu thang, lối đi. Đồng thời mang lại vẻ đẹp đơn giản, sang trọng hiện đại cho ngôi nhà của bạn, cũng sẽ là vật trang trí vô cùng cần thiết cho các công trình kiến trúc công cộng như nhà hàng, khách sạn, resort,…', 'Thiết kế cao cấp tối giản hiện đại\r\nVật liệu được lựa chọn kỹ càng\r\nKiểu dáng sáng tạo, độc đáo\r\nDễ dàng lắp đặt tại nhà\r\nTHÔNG SỐ:\r\n\r\nCông suất : LED 5W\r\nĐộ sáng : 350lm Max\r\nMàu ánh sáng: vàng ấm 2700K\r\nChỉ số hoàn màu: CRI>90\r\nKích thước: D13.5 x H7.5 cm\r\nChất liệu : Acrylic - nhôm\r\nĐiện áp: 220V\r\nKhông gian: Đèn tường trang trí phòng khách, phòng ăn\r\nLƯU Ý KHI LẮP ĐẶT\r\n- Đèn cần đấu **nguồn điện 220V riêng cho từng bóng** (đấu song song), không đấu nối tiếp nhiều đèn với nhau.\r\n- Trường hợp lắp nhiều đèn theo hàng, thợ điện cần chia nguồn song song để mỗi đèn nhận đủ điện áp.\r\n- Việc đấu nối tiếp có thể gây quá tải, dẫn đến cháy hỏng đèn.\r\n- Khuyến nghị lắp đặt bởi thợ điện có kinh nghiệm để đảm bảo an toàn.', 'DTA03', 600000.00, 'in_stock', 'Acrylic - nhôm', NULL, 12, 0.00, 0, 0, 1, '2026-05-20 12:12:26', '2026-05-20 05:12:26', '2026-05-23 17:32:39'),
(24, 3, 'Đèn bàn thủy tinh không dây, đèn ngoài trời trang trí bàn ăn có tay xách, sạc điện USB', 'dn-bn-thy-tinh-khng-dy-dn-ngoi-tri-trang-tr-bn-n-c-tay-xch-sc-din-usb', 'MÔ TẢ\r\n\r\nĐèn bàn LED thiết kế hiện đại với thân kim loại mờ kết hợp chụp đèn thủy tinh, tạo ánh sáng dịu nhẹ và sang trọng. Đèn có tay xách tiện lợi, có thể sử dụng linh hoạt trong nhà hoặc mang theo khi đi dã ngoại, cắm trại. Đèn hoạt động không dây, dễ dàng đặt ở bất kỳ vị trí nào.', 'THÔNG SỐ\r\n\r\n- Chất liệu: Kim loại sơn mờ + chụp thủy tinh\r\n\r\n- Kích thước: D13xH24 cm\r\n\r\n- Kiểu dáng: Đèn bàn hiện đại\r\n\r\n- Ánh sáng: LED ánh sáng 3 màu: vàng, trắng, trung tính, điều chỉnh tăng giảm ánh sáng (dimming) bằng cách nhấn giữ tay ở phần trên của đèn\r\n\r\n- Điều khiển: Cảm ứng chạm\r\n\r\n- Ng uồn điện: Sạc USB. Sạc đầy khoảng: 2 – 3 giờ. Thời gian sử dụng: Tùy mức sáng: Sáng mạnh: khoảng 1.5 – 2 giờ, Sáng trung bình: khoảng 3 – 4 giờ, Sáng nhẹ / đèn ngủ: khoảng 5 – 6 giờ\r\n\r\n- Sử dụng: Không dây, có tay xách tiện di chuyển\r\n\r\n- Phù hợp: Bàn tiệc trà ngoài trời, Bàn làm việc, phòng ngủ, ban công, dã ngoại\r\nGỢI Ý SỬ DỤNG\r\n\r\n- Đèn bàn trang trí phòng ngủ, bàn làm việc\r\n\r\n- Đèn bàn ngoài trời cho ban công, sân vườn\r\n\r\n- Đèn mang theo khi dã ngoại, cắm trại\r\n\r\n- Đèn decor quán cafe, homestay\r\n\r\n\r\n\r\nLƯU Ý BẢO QUẢN\r\n\r\n- Sạc đầy pin trước khi sử dụng lần đầu\r\n\r\n- Tránh để đèn tiếp xúc nước lâu\r\n\r\n- Lau bằng khăn khô để giữ bề mặt kim loại đẹp\r\n\r\n- Không va đập mạnh vào phần chụp thủy tinh', 'DBA02', 540000.00, 'in_stock', 'Thủy tinh', NULL, 12, 0.00, 0, 0, 1, '2026-05-24 02:19:27', '2026-05-23 19:19:27', '2026-05-23 19:20:50'),
(25, 3, 'Đèn bàn khối lập phương chiều lồng khung kính, chao đèn giấy gạo phong cách Nhật Bản', 'dn-bn-khi-lp-phng-chiu-lng-khung-knh-chao-dn-giy-go-phong-cch-nht-bn', 'ĐÈN BÀN PHONG CÁCH NHẬT', '1. MÔ TẢ:\r\nĐèn bàn thiết kế hình lập phương, lấy cảm hứng từ kiến trúc Nhật hiện đại. Lõi đèn là lớp giấy nghệ thuật ánh vàng ấm, bọc ngoài bởi khung kính trong suốt tạo chiều sâu thị giác. Phù hợp cho mọi không gian cần ánh sáng dịu nhẹ, vừa làm đèn ngủ vừa làm điểm nhấn decor nội thất.\r\n\r\n2. THÔNG SỐ:\r\n- Kích thước: 20x20x24cm  \r\n- Chất liệu: Hợp kim + giấy + kính  \r\n- Nguồn sáng: LED tích hợp sẵn  \r\n- Công suất: 5W trở xuống  \r\n- Điện áp: 111–240V  \r\n- Kiểu điều khiển: Công tắc sạc  \r\n- Phong cách: Nhật  \r\n- Bảo hành: 3 năm  \r\n- Ứng dụng: Phòng khách, phòng ngủ, phòng trà, salon, studio, góc đọc sách  \r\n\r\n\r\n3. GỢI Ý SỬ DỤNG:\r\n- Đặt trên bàn làm việc, kệ đầu giường, quầy tiếp tân hoặc góc decor tĩnh  \r\n- Phối hợp nội thất phong cách tối giản, hiện đại, Japandi hoặc vintage  \r\n- Sử dụng làm quà tặng cho người yêu decor, người làm nghề sáng tạo  \r\n\r\n4. LƯU Ý BẢO QUẢN:\r\n- Tránh đặt nơi ẩm ướt hoặc ánh nắng trực tiếp  \r\n- Lau nhẹ phần kính bằng khăn mềm  \r\n- Khi sạc pin, nên dùng nguồn ổn định, tránh vừa dùng vừa sạc nếu không cần thiết', 'DBB018', 1950000.00, 'in_stock', 'Thủy tinh+giấy', 'Trắng', 12, 0.00, 0, 0, 1, '2026-05-24 02:22:50', '2026-05-23 19:22:50', '2026-05-23 19:23:16'),
(26, 3, 'Đèn bàn cổ điển Matsutake', 'dn-bn-c-din-matsutake', 'ĐÈN BÀN MATSUTAKE', 'THÔNG SỐ:\r\n\r\n- Kích thước: XEM HÌNH\r\n\r\n- Bóng đèn led G9* 3 bóng đèn, 3 màu: trắng, vàng, trung tính\r\n\r\n- Vật liệu: thủy tinh\r\n\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\n \r\n\r\nCÔNG DỤNG:\r\n\r\n- Cung cấp ánh sáng ấm áp, đặt trên bàn cạnh giường ngủ hoặc làm một chiếc đèn đọc sách hoàn hảo.\r\n\r\n- Phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\n\r\n- Ánh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DBB014', 1800000.00, 'in_stock', 'Gỗ+thủy tinh', 'Trắng', 12, 0.00, 0, 0, 1, '2026-05-24 02:25:18', '2026-05-23 19:25:18', '2026-05-23 19:25:28'),
(27, 3, 'Đèn bàn thân đá Travertine, đèn ngủ để đầu giường, đèn đọc sách thiết kế Đan Mạch', 'dn-bn-thn-d-travertine-dn-ng-d-du-ging-dn-dc-sch-thit-k-dan-mch', 'ĐÈN BÀN TRAVERTINE\r\n\r\nÁnh sáng khuếch tán đều trên thân đá chưa gia công, nguyên bản để ánh sáng làm nổi bật những điểm không hoàn hảo tự nhiên của đá, để lộ những mảng sáng tối đan xen như một cách chơi màu sắc hấp dẫn.', 'THÔNG SỐ:\r\n\r\nKích thước: Cao 30 x đường kính 25 cm\r\nNguồn sáng: đèn led G9* 3 bóng đèn, 3 màu: trắng, vàng, trung tính\r\nVật liệu: Đá travertine, nhôm\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nCung cấp ánh sáng ấm áp, đặt trên bàn cạnh giường ngủ hoặc làm một chiếc đèn đọc sách hoàn hảo.\r\nPhù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DBB011', 900000.00, 'in_stock', 'Đá nguyên khối', 'Đen', 12, 0.00, 0, 0, 1, '2026-05-24 02:26:59', '2026-05-23 19:26:59', '2026-05-23 19:27:12'),
(28, 3, 'Đèn bàn Banker chao thủy tinh xanh bóng đèn 3 chế độ sáng WINSUM', 'dn-bn-banker-chao-thy-tinh-xanh-bng-dn-3-ch-d-sng-winsum', 'ĐÈN BÀN BANKER LAMP', '- Đèn được thiết kế và sản xuất dành cho Ngân hàng, các văn phòng lớn, thư viện … đầu những năm 50-60.\r\n\r\n- Rất nhiều bộ phim nổi tiếng trong bối cảnh những năm đó cho đến nay đã sử dụng Banker Lamp làm đạo cụ như Se7en (Morgan Freeman và Brad Pitt đóng), Người nghe tiếng gió (Lương Triều Vĩ, Châu Tấn),... Nếu bạn là một tín đồ của điện ảnh, bạn chắc chắn đã bắt gặp hình ảnh của chiếc đèn này rất nhiều lần.\r\n\r\nTHÔNG SỐ:\r\n\r\nKích thước: Đế đường kính 18 cm, Chiều cao 36 cm, Chiều dài chụp đèn 25 cm.\r\nChất liệu: Thân đèn: hợp kim mạ, chụp đèn: thuỷ tinh cao cấp\r\nCông tắc kéo giật', 'DBB04', 810000.00, 'in_stock', 'Thủy tinh', 'Xanh', 12, 0.00, 0, 0, 1, '2026-05-24 02:29:16', '2026-05-23 19:29:16', '2026-05-23 19:29:16'),
(29, 3, 'Đèn nordic để bàn làm việc, khung hợp kim điều chỉnh, bóng đèn 3 chế độ sáng bảo vệ mắt', 'dn-nordic-d-bn-lm-vic-khung-hp-kim-diu-chnh-bng-dn-3-ch-d-sng-bo-v-mt', 'Chia sẻ\r\n \r\nĐèn nordic để bàn làm việc, khung hợp kim điều chỉnh, bóng đèn 3 chế độ sáng bảo vệ mắt', 'THÔNG SỐ:\r\n\r\nChất liệu: kim loại\r\nKích thước: đường kính đế 17 x chiều cao 52 x đường kính chao đèn 12 cm\r\nBóng đèn: LED 7W, ánh sáng màu vàng\r\nVùng sáng: 6 - 18 m vuông\r\nThay đổi được 3 màu ánh sáng: vàng - vàng trắng - trắng', 'DBB01', 1050000.00, 'in_stock', 'Kim loại', 'Bạc', 12, 0.00, 0, 0, 1, '2026-05-24 02:30:29', '2026-05-23 19:30:29', '2026-05-23 19:31:09'),
(30, 3, 'Đèn đặt bàn AKARI phong cách Nhật Bản, chất liệu giấy gạo cao cấp', 'dn-dt-bn-akari-phong-cch-nht-bn-cht-liu-giy-go-cao-cp', 'Đèn đặt bàn AKARI phong cách Nhật Bản, chất liệu giấy gạo cao cấp - DBA01\r\nMã sản phẩm: DBA01', 'THÔNG SỐ:\r\n\r\nKích thước: chiều cao khoảng 43cm, rộng khoảng 26 cm (vui lòng cho phép sai số 1-3 cm)\r\nChụp đèn làm từ giấy gạo cao cấp. Khung kim loại sơn tĩnh điện chổng gỉ chắc chắn\r\nBóng đèn LED ánh sáng vàng.\r\nĐui đèn: E27\r\nCông suất: 7W', 'DBA01', 540000.00, 'in_stock', 'Giấy', 'Trắng', 12, 0.00, 0, 0, 1, '2026-05-24 02:32:28', '2026-05-23 19:32:28', '2026-05-23 19:32:28'),
(31, 3, 'Đèn bàn cổ điển 3 chân BB origami, tán xếp ly thân gỗ nguyên khối', 'dn-bn-c-din-3-chn-bb-origami-tn-xp-ly-thn-g-nguyn-khi', 'Phần chụp đèn kiểu gấp origami đơn giản nhưng thanh lịch mang đến cho chiếc đèn này một vẻ ngoài đơn giản nhưng thanh lịch. Thiết kế đơn giản cũng khiến nó trở thành một chiếc đèn tuyệt vời cho bất kỳ ai sử dụng trong mọi phòng trong nhà. Phong cách cá tính, bắt mắt chắc chắn sẽ tạo thêm điểm nhấn độc đáo cho bất kỳ căn phòng nào.', 'THÔNG SỐ:\r\n\r\n- Kích thước:đường kính 40cm, chiều cao 38.5cm \r\n\r\n- Ng uồn sáng: đèn led E14, 12W\r\n\r\n- Chất liệu chao đèn: nhựa vải PC\r\n\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\n \r\n\r\nCÔNG DỤNG:\r\n\r\n- Phù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\n\r\n- Ánh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DBB010', 1050000.00, 'in_stock', 'nhựa vải PC', 'Cam', 12, 0.00, 0, 0, 1, '2026-05-24 02:34:15', '2026-05-23 19:34:15', '2026-05-23 19:34:15'),
(32, 3, 'Đèn bàn thân gỗ, chụp đèn kim loại kiểu cổ điển 2 bóng đèn, đèn trang trí bàn làm việc', 'dn-bn-thn-g-chp-dn-kim-loi-kiu-c-din-2-bng-dn-dn-trang-tr-bn-lm-vic', 'ĐÈN BÀN THÂN GỖ', 'THÔNG SỐ:\r\n\r\nKích thước:đường kính 30cm, chiều cao 40cm\r\nNguồn sáng: đèn led E27, 12W\r\nChất liệu: thân gỗ, inox không gỉ\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nPhù hợp trang trí nội thất phong cách cổ điển, trang trí studio, cửa hàng,...\r\nÁnh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DBB09', 1050000.00, 'in_stock', 'Kim loại sơn tĩnh điện', 'Gỗ', 12, 0.00, 0, 0, 1, '2026-05-24 02:35:34', '2026-05-23 19:35:34', '2026-05-23 19:37:33'),
(33, 3, 'Đèn để bàn thân gỗ nguyên khối, chao vải da phong cách vintage, đèn hình nấm', 'dn-d-bn-thn-g-nguyn-khi-chao-vi-da-phong-cch-vintage-dn-hnh-nm', 'ĐÈN THÂN GỖ HÌNH NẤM CHAO GIẤY DA', 'THÔNG SỐ:\r\n\r\nNg uồn sáng: bóng đèn led 3 màu\r\nChất liệu: thân gỗ, chao PVC giấy da\r\nKích thước: đường kính đế 10 cm, cao 41 cm, đường kính chao đèn 22 cm\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\n\r\nCÔNG DỤNG:\r\n\r\nPhong cách đơn giản, nhẹ nhàng kết hợp màu gỗ nâu và chao đèn vải mang lại cảm giác thanh lịch, sang trọng\r\nCảm giác cổ điển, mộc mạc, độc đáo\r\nÁnh sáng ấm áp', 'DBB08', 810000.00, 'in_stock', 'Gỗ', 'Gỗ', 12, 0.00, 0, 0, 1, '2026-05-24 02:37:19', '2026-05-23 19:37:19', '2026-05-23 19:37:19'),
(34, 3, 'Đèn bàn thân đá chao thủy tinh sang trọng', 'dn-bn-thn-d-chao-thy-tinh-sang-trng', 'Đèn có phần đế làm từ đá tự nhiên chắc chắn được thiết kế đơn giản, nhỏ gọn mà không kém phần sang trọng và hiện đại, thích hợp với đa dạng không gian như phòng khách, phòng ngủ, phòng làm việc mang lại cảm giác thoải mái cho người dùng.', 'Phù hợp dùng làm đèn trang trí phòng khách, phòng ngủ, để bàn làm việc, bàn trang điểm, đèn để bàn đọc sách trong các căn chung cư, biệt thự, để trang trí bàn bar, quầy lễ tân toà nhà, quán cà phê, khách sạn…\r\n\r\n– Chất liệu: Chân đế bằng đá, chao thuỷ tinh\r\n– Kích thước: Chiều cao 24cm, đường kính chao 23cm\r\n– Loại bóng: LED đui E27, ánh sáng vàng', 'DBB012', 1200000.00, 'in_stock', 'Thủy tinh', 'Khói', 12, 0.00, 0, 0, 1, '2026-05-24 02:39:35', '2026-05-23 19:39:35', '2026-05-23 19:39:50'),
(35, 4, 'Đèn sàn Lumina Dalphine, đèn đọc sách điều chỉnh độ sáng phong cách công nghiệp', 'dn-sn-lumina-dalphine-dn-dc-sch-diu-chnh-d-sng-phong-cch-cng-nghip', 'ĐÈN SÀN LUMINA', 'THÔNG SỐ:\r\n\r\nKích thước: Cao 91 cm\r\nĐèn LED ánh sáng ấm, có thể tăng giảm độ sáng\r\nVật liệu: thân đèn sắt mạ niken, có thể điều chỉnh độ cao và hướng chiếu sáng\r\n(Vui lòng cho phép sai số do đo thủ công 1-3 cm)\r\nCÔNG DỤNG:\r\n\r\nCung cấp ánh sáng ấm áp, đặt bên bàn làm việc, ghế sofa, làm một chiếc đèn đọc sách hoàn hảo.\r\nPhù hợp trang trí nội thất nhiều phong cách phong cách\r\nÁnh sáng vàng ấm dịu, ấm áp tạo không gian thoải mái, thư giãn', 'DSA05', 3600000.00, 'in_stock', 'Kim loại sơn tĩnh điện', 'Bạc', 12, 0.00, 0, 0, 1, '2026-05-24 02:41:48', '2026-05-23 19:41:48', '2026-05-23 19:41:48');

